using RestSharp;
using Newtonsoft;
using UBSInterfaceToolkit.TokenToolkit;

internal final class UBSOutboundInterfaceTest
{
}

Method.Source:
    /// <summary>
    /// Class entry point. The system will call this method when a designated menu 
    /// is selected or when execution starts and this class is set as the startup class.
    /// </summary>
    /// <param name = "_args">The specified arguments.</param>
    public static void main(Args _args)
    {
        UBSOutboundInterfaceTest testInterface = new UBSOutboundInterfaceTest();

        //str bearer = testInterface.getBearer();
        testInterface.sendFinancialDimension();
    }

    public str getBearer()
    {
        UBSOutboundInterface outboundInterface =  UBSOutboundInterface::findUBSOutboundInterface();

        str AccessToken = UBSInterfaceToolkit.TokenToolkit::getToken(outboundInterface.UBSRootURLAuthentication, outboundInterface.UBSTenantId,
            outboundInterface.UBSEndURLAuthentication,outboundInterface.UBSClientId,UBSOutboundInterface::findPassword(),outboundInterface.UBSGrantType,outboundInterface.UBSScope);
 
        return AccessToken;
    }

    public void sendFinancialDimension()
    {
        System.Collections.ArrayList financialDimensionList = new System.Collections.ArrayList();

        FinancialDimensionValueEntity financialDimensionValue ;

        while select financialDimensionValue 
        {

            financialDimensionList.Add([financialDimensionValue.FinancialDimension,
                                        financialDimensionValue.DimensionValue,
                                        financialDimensionValue.Description,
                                        enum2int(financialDimensionValue.IsSuspended)]);
        }

        str bearer = this.getBearer();
        UBSOutboundInterface outboundInterface =  UBSOutboundInterface::findUBSOutboundInterface();
        str endPoint = UBSOutboundInterfaceEndPoint::findByEndPointType(UBSEndPointType::FinancialDimension).UBSEndPoint;

        UBSInterfaceToolkit.EndPoint::BuildRequest(outboundInterface.UBSResource,
                                                   outboundInterface.UBSResourceRequest,
                                                   endPoint,
                                                   bearer,
                                                   financialDimensionList,
                                                   enum2int(UBSEndPointType::FinancialDimension),
                                                   enum2int(outboundInterface.UBSDebugMode));

    }
